UPDATE email_templates SET body_template = 'Bonjour {{prenom}},<br><br>Nous faisons suite à votre demande d''inscription à la <strong>Formation Continue {{formation}}</strong> du <strong>{{date_debut}}</strong> au <strong>{{date_fin}}</strong>.<br><br><span style="color: red; font-size: 16px; font-weight: bold;">⚠️ ATTENTION : À ce jour, nous n''avons reçu aucun règlement de votre part. Votre inscription n''est donc PAS validée et vous ne pourrez PAS accéder à la Formation Continue.</span><br><br>Si vous souhaitez confirmer votre inscription à la <strong>Formation Continue {{formation}}</strong>, vous devez effectuer un <strong>virement bancaire immédiat</strong> aux coordonnées suivantes :<br><br><strong>RIB - SASU SERVICES PRO F TRANSPORT</strong><br><br>Destinataire : SERVICES PRO<br>Adresse : 86 ROUTE DE GENAS, 69003, LYON, France<br>IBAN : FR76 2823 3000 0185 7527 9099 426<br>BIC : REVOFRP2<br><br>Sans réception du virement, votre place sera automatiquement libérée et attribuée à un autre candidat.<br><br><strong>Si vous avez déjà effectué le virement</strong>, merci de nous envoyer immédiatement la <strong>preuve de virement</strong> (capture d''écran ou justificatif bancaire) par retour de mail à <strong>contact@ftransport.fr</strong> afin que nous puissions valider votre inscription dans les plus brefs délais.<br><br>Cordialement,<br><br>FTRANSPORT<br>Centre de formation<br>86 Route de Genas 69003 Lyon<br>📞 04.28.29.60.91<br>📧 contact@ftransport.fr', updated_at = now() WHERE id = 'relance-paiement-fc';